def normalize_shape(shape):
    # Translate shape to start at (0, 0)
    min_x = min(x for x, y in shape)
    min_y = min(y for x, y in shape)
    translated = tuple(sorted((x - min_x, y - min_y) for x, y in shape))

    # Generate all rotations and reflections
    transformations = set()
    for _ in range(4):
        translated = rotate_shape(translated)
        transformations.add(translated)
        transformations.add(reflect_shape(translated))

    return min(transformations)

def rotate_shape(shape):
    return tuple(sorted((y, -x) for x, y in shape))

def reflect_shape(shape):
    return tuple(sorted((-x, y) for x, y in shape))

