def generate_shapes(n):
    if n == 1:
        return [[[1]]]

    shapes = []
    visited = set()

    def can_place(shape, x, y, board):
        for dx, dy in shape:
            if not (0 <= x + dx < len(board) and 0 <= y + dy < len(board)):
                return False
            if board[x + dx][y + dy] != 0:
                return False
        return True

    def place(shape, x, y, board, value):
        for dx, dy in shape:
            board[x + dx][y + dy] = value

    def remove(shape, x, y, board):
        for dx, dy in shape:
            board[x + dx][y + dy] = 0

    def dfs(shape, x, y, board):
        if len(shape) == n:
            shape_tuple = tuple(sorted(shape))
            if shape_tuple not in visited:
                visited.add(shape_tuple)
                shapes.append(shape)
            return

        for dx in range(-1, 2):
            for dy in range(-1, 2):
                if abs(dx) + abs(dy) == 1:  # Only consider adjacent squares
                    new_shape = shape + [(dx, dy)]
                    if can_place(new_shape, x, y, board):
                        place(new_shape, x, y, board, 1)
                        dfs(new_shape, x, y, board)
                        remove(new_shape, x, y, board)

    board = [[0] * (n + 2) for _ in range(n + 2)]
    dfs([], 0, 0, board)

    return shapes

def count_unique_shapes(n):
    shapes = generate_shapes(n)
    return len(shapes), shapes

